```class Solution {
    public boolean reorderedPowerOf2(int n) {
        int count[] = new int[10];
        int temp = n;
        while (temp > 0) {
            count[temp % 10]++;
            temp /= 10;
        }
        for (int i = 0; i < 10; i++) {
            if (count[i] > 0) {
                int power = 1;
                while (power < 1024) {
                    int[] count2 = new int[10];
                    int temp2 = power;
                    while (temp2 > 0) {
                        count2[temp2 % 10]++;
                        temp2 /= 10;
                    }
                    boolean flag = true;
                    for (int j = 0; j < 10; j++) {
                        if (count[j] != count2[j]) {
                            flag = false;
                            break;
                        }
                    }
                    if (flag) return true;
                    power *= 2;
                }
            }
        }
        return false;
    }
}```
